import { useEffect, useState } from "react";
import axios from "axios";

function Dashboard() {

  const [subscriptions, setSubscriptions] = useState([]);

  useEffect(() => {
    fetchSubscriptions();
  }, []);

  const fetchSubscriptions = async () => {
    try {
      const res = await axios.get("http://localhost:5000/subscriptions");
      setSubscriptions(res.data);
    } catch (error) {
      console.log(error);
    }
  };

  const totalMonthly = subscriptions.reduce((total, sub) => {
    return total + Number(sub.cost);
  }, 0);

  return (
    <div className="dashboard">

      <h2>Subscription Dashboard</h2>

      <h3>Total Monthly Spend: ₹{totalMonthly}</h3>

      <table>
        <thead>
          <tr>
            <th>Service</th>
            <th>Cost</th>
            <th>Billing</th>
            <th>Renewal</th>
            <th>Category</th>
          </tr>
        </thead>

        <tbody>
          {subscriptions.map((sub) => (
            <tr key={sub._id}>
              <td>{sub.name}</td>
              <td>₹{sub.cost}</td>
              <td>{sub.billingCycle}</td>
              <td>{new Date(sub.renewalDate).toLocaleDateString()}</td>
              <td>{sub.category}</td>
            </tr>
          ))}
        </tbody>

      </table>

    </div>
  );
}

export default Dashboard;
